function applyTradeoffs(c,k,v,b){const u={...c,[k]:v};const d=v-b[k];const n=(key,a)=>{u[key]=Math.min(100,Math.max(0,(c[key]||50)+a))};if(k==="premium"){n("deductible",-d*0.6);n("network",d*0.3);n("copay",-d*0.3)}else if(k==="network")n("premium",d*0.4);else if(k==="deductible"){n("premium",-d*0.5);n("oop",d*0.4)}else if(k==="rx")n("premium",d*0.3);return u}
function generatePlan(sl,age,zip,income){const m=age>=60?1.6:age>=55?1.4:1.2;const fp=income/15060;let sf=0;if(fp<1.5)sf=0.97;else if(fp<2)sf=0.85;else if(fp<2.5)sf=0.72;else if(fp<3)sf=0.60;else if(fp<4)sf=0.40;const raw=650*m*(0.6+sl.premium/250),sub=raw*sf,net=Math.max(0,raw-sub);return{name:`${sl.premium<35?"Bronze":sl.premium<55?"Silver":sl.premium<72?"Gold":"Platinum"} ${sl.network>65?"Broad PPO":sl.network>45?"Mid-size EPO":"HMO"} Plan`,monthlyPremium:Math.round(net),annualPremium:Math.round(net*12),deductible:Math.round((500+sl.deductible*60)/100)*100,oopMax:Math.round((2000+sl.oop*60)/100)*100,copay:Math.round((15+sl.copay*0.45)/5)*5,subsidyAmount:Math.round(sub),rxTier:sl.rx>65?"Comprehensive":sl.rx>40?"Standard":"Generics only"}}

// ─── MEDICARE RECOMMENDATION LOGIC ───
function generateMedicareRec(data) {
  const { doctors=[], prescriptions=[], zip="", preference="", dependents="", empSize="" } = data;
  const hasDocs = doctors.length > 0;
  const hasRx = prescriptions.length > 0;
  const hasComplexRx = prescriptions.length >= 3 || prescriptions.some(p => p.tier === "specialty" || p.tier === "preferred-brand");
  const manyDocs = doctors.length >= 3;
  const warnings = [];

  // Flag dependents edge case
  if ((empSize === "small" || empSize === "unsure") && (dependents === "spouse" || dependents === "kids" || dependents === "spouse-kids")) {
    warnings.push({ type: "warning", badge: "Family", title: "Your family's coverage may be affected", text: "Medicare only covers you. If you drop your employer plan, your spouse or dependents will need separate coverage — through another employer, the ACA marketplace, or CHIP for children." });
  }

  let recommend = "medigap"; // default safer option
  const reasons = [];

  if (preference === "cheaper") {
    recommend = "ma";
    reasons.push({ type: "info", badge: "Cost", title: "You're prioritizing lower costs", text: "Medicare Advantage plans often have $0 or very low monthly premiums, plus extra benefits like dental, vision, and hearing." });
    // But override if complex needs
    if (manyDocs || hasComplexRx) {
      warnings.push({ type: "info", badge: "Heads Up", title: "Your medical needs may point toward broader coverage", text: "You have multiple doctors or complex prescriptions. While Medicare Advantage can be cheaper, a Medigap plan gives you unrestricted access to any doctor and more predictable costs. It's worth comparing both carefully." });
    }
    if (manyDocs) {
      reasons.push({ type: "info", badge: "Network", title: "Check your doctors are in-network", text: "Medicare Advantage plans use networks (HMO/PPO). You'll want to verify your doctors participate before enrolling." });
    }
  } else if (preference === "similar") {
    recommend = "medigap";
    reasons.push({ type: "info", badge: "Coverage", title: "You want similar coverage to what you have", text: "A Medigap supplement plan + standalone Part D gives you the most comprehensive, predictable coverage — similar to what a good employer plan provides." });
    reasons.push({ type: "info", badge: "Access", title: "Any doctor that accepts Medicare", text: "With Original Medicare + Medigap, you can see any provider nationwide that accepts Medicare. No referrals, no network restrictions." });
  } else if (preference === "better") {
    recommend = "medigap";
    reasons.push({ type: "info", badge: "Coverage", title: "You want the strongest coverage available", text: "Medigap Plan G or Plan N paired with a Part D drug plan gives you the most comprehensive Medicare coverage — minimal out-of-pocket surprises." });
    reasons.push({ type: "info", badge: "Predictable", title: "Predictable costs, broad access", text: "With Medigap, your annual out-of-pocket costs are highly predictable. No surprise bills, no network hassles." });
  }

  // Additional context
  if (recommend === "ma") {
    reasons.push({ type: "medicare", badge: "Extras", title: "Medicare Advantage often includes extras", text: "Many MA plans include dental, vision, hearing, gym memberships, and OTC allowances at no extra cost." });
    if (hasRx) {
      reasons.push({ type: "info", badge: "Rx", title: "Drug coverage is usually built in", text: "Most Medicare Advantage plans include Part D drug coverage. Your specific medications should be checked against the plan's formulary." });
    }
  } else {
    reasons.push({ type: "medicare", badge: "Part D", title: "You'll need a standalone Part D plan", text: "Medigap doesn't include drug coverage. You'll pair it with a separate Part D prescription drug plan matched to your specific medications." });
    if (hasDocs) {
      reasons.push({ type: "info", badge: "Doctors", title: "Your doctors are covered", text: "With Original Medicare + Medigap, any doctor that accepts Medicare is in your 'network.' No need to check provider directories." });
    }
  }

  return { recommend, reasons, warnings };
}

// ─── EMPLOYER ANALYSIS LOGIC (20+ branch) ───
function generateEmployerAnalysis(data) {
  const { premium="", deductible="", oopMax="", dependents="", networkSat="" } = data;
  const p = parseFloat(premium) || 0, d = parseFloat(deductible) || 0, o = parseFloat(oopMax) || 0;
  let ms = 0, es = 0;
  const factors = [];

  if (p > 500) { factors.push({ type: "medicare", badge: "Cost", title: "High monthly premium", text: "At over $500/month, Medicare is likely cheaper — Part B is $174.70/month (2025) plus a supplement." }); ms += 3; }
  else if (p > 200) { factors.push({ type: "info", badge: "Cost", title: "Moderate premium — worth comparing", text: `$${p}/month is in the range where Medicare could be competitive. A side-by-side comparison will tell you.` }); ms += 1; }
  else if (p > 0) { factors.push({ type: "employer", badge: "Cost", title: "Low premium — strong employer subsidy", text: "Your employer is covering a significant share. Medicare + supplement may cost more." }); es += 3; }

  if (d > 4000) { factors.push({ type: "medicare", badge: "Deductible", title: "High deductible exposure", text: "Medigap plans can reduce your deductible exposure to near-zero." }); ms += 2; }
  else if (d > 0 && d <= 1500) { factors.push({ type: "employer", badge: "Deductible", title: "Reasonable deductible", text: `$${d} deductible is manageable and competitive with Medicare options.` }); es += 1; }

  if (o > 8000) { factors.push({ type: "medicare", badge: "OOP Max", title: "High out-of-pocket maximum", text: "Medigap essentially eliminates surprise costs. Your current $" + o.toLocaleString() + " max is higher than what most Medigap enrollees ever pay." }); ms += 2; }
  else if (o > 0 && o <= 4000) { factors.push({ type: "employer", badge: "OOP Max", title: "Good out-of-pocket protection", text: `$${o.toLocaleString()} OOP max provides solid protection.` }); es += 1; }

  if (dependents === "kids" || dependents === "spouse-kids") { factors.push({ type: "employer", badge: "Family", title: "Dependents on your plan", text: "Medicare only covers you. Dropping your employer plan means finding separate coverage for your family." }); es += 3; }
  else if (dependents === "spouse") { factors.push({ type: "info", badge: "Spouse", title: "Spouse needs their own coverage", text: "Your spouse will need their own plan — employer, marketplace, or Medicare if 65+." }); }

  if (networkSat === "limited") { factors.push({ type: "medicare", badge: "Network", title: "You feel limited by your current network", text: "Original Medicare has no network — any provider that accepts Medicare, nationwide." }); ms += 2; }
  else if (networkSat === "happy") { factors.push({ type: "employer", badge: "Network", title: "You're happy with your coverage", text: "If your providers and benefits work well, that's a real advantage to keep." }); es += 2; }

  const total = ms + es, ratio = total > 0 ? ms / total : 0.5;
  let verdict;
  if (ratio > 0.6) verdict = { type: "medicare", label: "Based on your answers", title: "Medicare may be a better fit", text: "Several factors suggest Medicare could save you money or improve your coverage. Let's find the right Medicare plan.", showContinue: true, color: "#3b82f6", bg: "#eff6ff", border: "#3b82f6" };
  else if (ratio < 0.4) verdict = { type: "employer", label: "Based on your answers", title: "Your employer plan looks competitive", text: "Your current plan has meaningful advantages. That said, it's always worth having an advisor do a precise side-by-side comparison.", showContinue: false, color: "#eab308", bg: "#fefce8", border: "#eab308" };
  else verdict = { type: "close", label: "Based on your answers", title: "It's a close call", text: "Meaningful factors on both sides. A personalized comparison will make this much clearer.", showContinue: true, color: TEXT_MED, bg: BG_SUBTLE, border: BORDER };
  return { factors, verdict, barWidth: Math.round(ratio * 100), barColor: verdict.color };
}


