const MG_BASE_PREMIUMS = {
  G:{65:145,67:160,70:180,72:200,75:225,78:260,80:290},
  N:{65:110,67:120,70:140,72:155,75:175,78:200,80:225},
  G_HD:{65:65,67:72,70:82,72:90,75:105,78:120,80:135}
};

function getBasePremium(plan, age) {
  const p = MG_BASE_PREMIUMS[plan] || MG_BASE_PREMIUMS.G;
  const ages = Object.keys(p).map(Number).sort((a,b)=>a-b);
  // Interpolate
  if (age <= ages[0]) return p[ages[0]];
  if (age >= ages[ages.length-1]) return p[ages[ages.length-1]];
  for (let i = 0; i < ages.length - 1; i++) {
    if (age >= ages[i] && age <= ages[i+1]) {
      const frac = (age - ages[i]) / (ages[i+1] - ages[i]);
      return Math.round(p[ages[i]] + frac * (p[ages[i+1]] - p[ages[i]]));
    }
  }
  return p[ages[ages.length-1]];
}

// ─── CARRIER SCORING ───
function scoreCarrier(c, plan, state) {
  if (c.unavailable.includes(state)) return null;
  const isCommunityState = state === "NY" || state === "CT";
  const methScore = isCommunityState ? 20 : c.method === "community" ? 20 : c.method === "issue_age" ? 15 : 0;
  const avgInc = plan === "N" ? c.planNInc : c.planGInc;
  let rateScore = avgInc < 0.06 ? 25 : avgInc < 0.08 ? 15 : avgInc < 0.10 ? 5 : -10;
  if (c.trend === "rising") rateScore -= 10;
  if (c.trend === "falling") rateScore += 5;
  rateScore = Math.max(-20, rateScore);
  const naicScore = Math.max(0, Math.min(15, Math.floor((1.0 - c.naic) * 15 + 15)));
  const total = c.amBestScore + methScore + rateScore + naicScore + 10;
  return { ...c, total, avgInc, methScore, rateScore, naicScore };
}

// ─── 10-YEAR COST MODEL ───
function tenYearCost(monthlyPremium, avgInc, method, age) {
  const years = [];
  let total = 0;
  for (let y = 0; y < 10; y++) {
    const genFactor = Math.pow(1 + avgInc, y);
    let ageFactor = 1;
    if (method === "attained_age") {
      const a = age + y;
      if (a < 70) ageFactor = Math.pow(1.018, y);
      else if (a < 75) ageFactor = Math.pow(1.018, Math.min(y,5)) * Math.pow(1.025, Math.max(0, y - 5));
      else ageFactor = Math.pow(1.018, 5) * Math.pow(1.025, 5) * Math.pow(1.030, Math.max(0, y - 10));
    }
    const annual = monthlyPremium * 12 * genFactor * ageFactor;
    total += annual;
    years.push({ year: y + 1, monthly: Math.round(annual / 12), annual: Math.round(annual) });
  }
  return { years, total10yr: Math.round(total), yr5Monthly: years[4]?.monthly, yr10Monthly: years[9]?.monthly };
}

// ─── FULL MEDIGAP ENGINE ───
function csgMatchMedigap(needs, zip, prescriptions, preference) {
  const state = zipToState(zip);
  // Nonstandard state check
  if (NONSTANDARD_STATES[state]) return { status:"advisor_referral", reason:NONSTANDARD_STATES[state], state };

  const age = needs.age || 66;
  const coverSit = needs.coverageSituation || "new_to_medicare";
  const health = needs.healthStatus || "good";
  const visits = needs.visitFreq === "frequently" ? 10 : needs.visitFreq === "regularly" ? 6 : 2;
  const hasChronic = health === "fair" || health === "poor";
  const planChoice = needs.planChoice; // user may have explicitly chosen

  // GI determination
  let giEligible = false, giReason = "";
  if (coverSit === "new_to_medicare" || coverSit === "employer_ending") {
    giEligible = true;
    giReason = coverSit === "new_to_medicare"
      ? "You're in your 6-month Medigap Open Enrollment Period — any carrier must accept you regardless of health."
      : "Your employer coverage ending gives you a federal Guaranteed Issue right — 63 days to enroll without underwriting.";
  } else if (GI_YEAR_ROUND_STATES[state]) {
    giEligible = true;
    giReason = GI_YEAR_ROUND_STATES[state];
  } else {
    giReason = coverSit === "ma_plan"
      ? "Switching from Medicare Advantage to Medigap typically requires medical underwriting. If you enrolled during your initial period and it's been less than 12 months, you may have Trial Rights."
      : "You'll need to pass medical underwriting for Medigap coverage.";
  }

  // Plan scoring
  let gScore = 0, nScore = 0, hdScore = 0;
  if (visits >= 6) gScore += 30;
  if (hasChronic) gScore += 25;
  if (health === "fair" || health === "poor") gScore += 20;
  if (age >= 70) gScore += 15;
  if (coverSit === "ma_plan") gScore += 15;
  if ((health === "excellent" || health === "good") && !hasChronic) nScore += 25;
  if (visits <= 3) nScore += 20;
  if (age <= 68 && coverSit === "new_to_medicare") nScore += 15;
  if (preference === "cheaper") nScore += 20;
  if (health === "excellent" && !hasChronic && age <= 67) hdScore += 30;
  // User explicit choice override
  if (planChoice === "plan-g") gScore += 40;
  if (planChoice === "plan-n") nScore += 40;

  const scores = [{p:"G",s:gScore},{p:"N",s:nScore},{p:"G_HD",s:hdScore}].sort((a,b) => b.s - a.s);
  const primaryPlan = scores[0].p;
  const showBoth = Math.abs(gScore - nScore) < 15;
  const secondaryPlan = showBoth && scores[1].p !== "G_HD" ? scores[1].p : null;

  // Carrier scoring
  let carriers = MG_CARRIERS.map(c => scoreCarrier(c, primaryPlan, state)).filter(Boolean);
  carriers.sort((a, b) => b.total - a.total);

  // 10-year cost models for top 3
  const basePrem = getBasePremium(primaryPlan, age);
  const topCarriers = carriers.slice(0, 3).map((c, i) => {
    const costModel = tenYearCost(basePrem, c.avgInc, c.method, age);
    return { ...c, rank: i + 1, basePremium: basePrem, costModel };
  });

  // Preferred carrier boost
  if (needs.carrier && needs.carrier !== "none") {
    const preferred = topCarriers.find(c => c.name === needs.carrier);
    if (!preferred) {
      const fromAll = carriers.find(c => c.name === needs.carrier);
      if (fromAll) {
        fromAll.costModel = tenYearCost(basePrem, fromAll.avgInc, fromAll.method, age);
        fromAll.rank = 0;
        fromAll.basePremium = basePrem;
        topCarriers.unshift(fromAll);
        if (topCarriers.length > 3) topCarriers.pop();
      }
    }
  }

  // State flags
  const stateFlags = [];
  if (GI_YEAR_ROUND_STATES[state]) stateFlags.push({ type:"gi_state", message:GI_YEAR_ROUND_STATES[state] });
  if (BIRTHDAY_RULE_STATES[state]) stateFlags.push({ type:"birthday_rule", message:BIRTHDAY_RULE_STATES[state].note });

  // Underwriting note
  let uwNote = "";
  if (giEligible) uwNote = "You have Guaranteed Issue rights — any carrier must accept you. This is your best window.";
  else if (health === "excellent" || health === "good") uwNote = "You'll need to pass medical underwriting. Based on your health profile, you should qualify with most carriers.";
  else if (health === "fair") uwNote = "Some carriers may be more selective given your health history. We'll help identify the most favorable underwriting.";
  else uwNote = "Based on your health history, Medigap may be difficult to qualify for. Medicare Advantage may be a better path.";

  // N upgrade warning
  const nUpgradeWarning = primaryPlan === "N" && !BIRTHDAY_RULE_STATES[state] && !GI_YEAR_ROUND_STATES[state];

  return {
    status:"recommendation", primaryPlan, secondaryPlan,
    planDetail: MG_PLANS[primaryPlan], planScores:{G:gScore,N:nScore,G_HD:hdScore},
    giEligible, giReason, topCarriers, stateFlags, uwNote, nUpgradeWarning, state,
    partDReminder:"Medigap does not cover prescriptions. You'll need a separate Part D plan.",
    basePremium: basePrem
  };
}


