              <button onClick={()=>{setCobra(c=>({...c,premium:String(cobraPlanId.premium),deductible:String(cobraPlanId.deductible),copay:String(cobraPlanId.copay),planType:(cobraPlanId.networkType||"ppo").toLowerCase(),matchedPlan:cobraPlanId}));setCobraPlanId(null);goTo(11)}} style={{display:"block",width:"100%",marginTop:8,background:"none",border:"none",color:TEXT_MED,padding:"10px",fontSize:13,fontWeight:600,fontFamily:heading,cursor:"pointer",textAlign:"center"}}>Let me adjust these numbers →</button>
