          {(()=>{const ageV=parseInt(cobra.age)>=18&&parseInt(cobra.age)<=100;const zipV=/^\d{5}$/.test(cobra.zip);const incV=parseFloat((cobra.income||"").replace(/[^0-9.]/g,""))>0;const ok=ageV&&zipV&&incV;return <button onClick={ok?handleCobraSliderStart:undefined} style={{width:"100%",marginTop:28,background:ok?GREEN:BORDER,color:ok?"#fff":TEXT_LIGHT,border:"none",padding:"14px 28px",borderRadius:10,fontSize:15,fontWeight:700,fontFamily:heading,cursor:ok?"pointer":"default",transition:"background 0.15s"}}>Continue →</button>})()}
