          {SLIDER_DEFS.map(d=><SliderRow key={d.key} def={d} value={sliders[d.key]} baseValue={baseSliders[d.key]} onChange={(k,v)=>{setSliders(applyTradeoffs(sliders,k,v,baseSliders));setMatchSimilar(false)}}/>)}
          {btn("Show Me My Comparison →",handleCobraResults)}
